import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import bookingService from '../services/bookingService';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../components/Toast';

export default function Bookings() {
  const { user } = useAuth();
  const showToast = useToast();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = () => {
    if (!user) { setLoading(false); return; }
    bookingService.getByUser(user.id)
      .then(setBookings)
      .catch(() => showToast('Could not load bookings', 'error'))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [user]);

  const cancelBooking = async (id) => {
    if (!window.confirm('Cancel this booking?')) return;
    try {
      await bookingService.cancel(id);
      showToast('Booking cancelled', 'success');
      load();
    } catch (e) {
      showToast(e.response?.data?.message || 'Could not cancel', 'error');
    }
  };

  if (!user) {
    return (
      <div className="container">
        <div className="empty-state">
          <div className="icon">🔐</div>
          <p>Please <Link to="/login" style={{ color: 'var(--primary)', fontWeight: 700 }}>login</Link> to view your bookings.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <h2 className="section-title">My Bookings</h2>
      {loading ? (
        <div className="loading-center"><div className="spinner"></div></div>
      ) : bookings.length === 0 ? (
        <div className="empty-state">
          <div className="icon">🎟️</div>
          <p>No bookings yet. <Link to="/movies" style={{ color: 'var(--primary)' }}>Book some movies!</Link></p>
        </div>
      ) : (
        <div className="bookings-list">
          {bookings.map(b => (
            <div
              className="card"
              key={b.id}
              style={{ border: b.status === 'CANCELLED' ? '1px solid rgba(233,69,96,0.3)' : '1px solid rgba(46,204,113,0.3)', marginBottom: '1rem' }}
            >
              <div className="card-body booking-card-body">
                <div>
                  <h3>🎬 {b.show?.movie?.title || 'Movie'}</h3>
                  <p>🏛️ {b.show?.screen?.theater?.name || ''} — {b.show?.screen?.name || ''}</p>
                  <p>📅 {b.show?.showDate || ''} &nbsp; 🕐 {b.show?.startTime || ''}</p>
                  <p>💺 Seats: {b.seats ? b.seats.map(s => s.seatNumber).join(', ') : 'N/A'}</p>
                  {b.bookedAt && <p>🕑 Booked: {new Date(b.bookedAt).toLocaleString()}</p>}
                </div>
                <div className="booking-meta">
                  <div className="price" style={{ color: b.status === 'CANCELLED' ? 'var(--accent)' : 'var(--success)' }}>
                    ₹{b.totalPrice || 0}
                  </div>
                  <span
                    className="badge"
                    style={{
                      background: b.status === 'CANCELLED' ? 'rgba(233,69,96,0.2)' : 'rgba(46,204,113,0.2)',
                      color: b.status === 'CANCELLED' ? 'var(--accent)' : 'var(--success)'
                    }}
                  >
                    {b.status}
                  </span>
                  {b.status === 'CONFIRMED' && (
                    <button className="btn btn-sm btn-danger" style={{ marginTop: '0.5rem' }} onClick={() => cancelBooking(b.id)}>
                      Cancel
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
